mapper.select:
SELECT c.id, c.type, COALESCE(ci.title, c.title) AS title, COALESCE(ci.summary, c.summary) AS summary, c.cover_url, c.source_url, c.published_at, c.status, c.created_at, COALESCE(s.like_count, 0) AS like_count, COALESCE(s.fav_count, 0) AS fav_count, COALESCE(s.comment_count, 0) AS comment_count, COALESCE(s.view_count, 0) AS view_count, COALESCE(s.hot_score, 0) AS hot_score FROM social.content c LEFT JOIN social.content_i18n ci ON ci.content_id = c.id AND ci.locale = #{locale} LEFT JOIN social.content_stats s ON c.id = s.content_id WHERE 1=1
AND c.type = #{type}
AND c.status = #{status}
ORDER BY
s.hot_score DESC NULLS LAST, c.published_at DESC NULLS LAST
c.created_at DESC, c.published_at DESC NULLS LAST
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM social.content c
WHERE 1=1

    AND c.type = #{type}


    AND c.status = #{status}
